function i(t,e){const n=Number.isFinite(e)?e:0;return`${t} ${n.toLocaleString("es-HN",{minimumFractionDigits:2,maximumFractionDigits:2})}`}function o(t){return(typeof t=="string"?new Date(t):t).toLocaleString("es-HN",{dateStyle:"short",timeStyle:"short"})}function r(t){return(typeof t=="string"?new Date(t):t).toLocaleDateString("es-HN",{dateStyle:"short"})}function a(t){return(typeof t=="string"?new Date(t):t).toLocaleTimeString("es-HN",{hour:"2-digit",minute:"2-digit"})}export{o as a,r as b,a as c,i as f};
